    try {
        val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
        val lastDump = prefs.getLong("last_forensic_dump_ts", 0L)
        val now = System.currentTimeMillis()

        // 12-HOUR GOVERNOR: Prevent storage bloat (2 dumps per day max)
        if (now - lastDump < 12 * 60 * 60 * 1000) {
            return
        }

        ensureMaze()
        val dateStr = SimpleDateFormat("d_M_yy", Locale.US).format(Date())
        val dayDir = File(ROOT_DIR, dateStr)
        if (!dayDir.exists()) dayDir.mkdirs()

        val timestamp = SimpleDateFormat("HH_mm_ss", Locale.US).format(Date())

        // 1. Readable Log (System diagnostics only)
        val logFile = File(dayDir, "sys_log_$timestamp.txt")
        val report = DeviceManager.getDiagnosticReport(ctx) + "\n\n--- LOGS ---\n" + DebugLogger.getLogs()
        logFile.writeText(report)

        // 2. Compressed & Encrypted Data Blob (.ctx extension)
        val jsonFile = File(dayDir, "data_snapshot_$timestamp.ctx")
        val rawJson = CloudManager.collectDumpData(ctx).toString()

        // Gzip -> Encrypt sequence
        val compressed = compressString(rawJson)
        val encrypted = encryptBytes(compressed)
        jsonFile.writeBytes(encrypted)

        prefs.edit().putLong("last_forensic_dump_ts", now).apply()
        DebugLogger.log("DUMP", "Forensic snapshot secured (${jsonFile.length() / 1024} KB)")
    } catch (e: Exception) {
        DebugLogger.log("DUMP_ERR", "Halt: ${e.message}")
    }
}

private fun compressString(data: String): ByteArray {
    val bos = java.io.ByteArrayOutputStream(data.length)
    java.util.zip.GZIPOutputStream(bos).use { it.write(data.toByteArray(Charsets.UTF_8)) }
    return bos.toByteArray()
}

